import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import cmsService from '../services/cmsService';

export default function DynamicPage() {
  const { slug } = useParams();
  const [page, setPage] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  console.log('DynamicPage rendered, slug from params:', slug);

  useEffect(() => {
    if (!slug) {
      setError('No slug provided');
      setLoading(false);
      return;
    }

    setLoading(true);
    const apiUrl = `https://ecennale-electricien-backend.ddev.site/api/pages/${slug}`;
    console.log('Fetching from:', apiUrl);

    fetch(apiUrl)
      .then(res => {
        console.log('Response status:', res.status);
        return res.json();
      })
      .then(data => {
        console.log('Full API Response:', data);
        if (data && data.slug) {
          setPage(data);
        } else if (data && data.error) {
          setError(data.error);
        } else {
          setError('Page not found');
        }
        setLoading(false);
      })
      .catch(err => {
        console.error('Fetch Error:', err);
        setError('Cannot connect to API');
        setLoading(false);
      });
  }, [slug]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-yellow-500"></div>
      </div>
    );
  }

  if (error || !page) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-gray-800 mb-2">Page non trouvée</h1>
          <p className="text-gray-600">{error || 'Cette page n\'existe pas ou n\'est pas publiée.'}</p>
          <p className="text-gray-400 text-sm mt-2">Slug: {slug}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white">
      {page.sections?.map((section) => (
        <section key={section.id} className={`py-12 md:py-16 ${section.type === 'hero' ? 'bg-yellow-500 text-white' : 'bg-white'}`}>
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            {section.title && (
              <h2 className={`text-3xl md:text-4xl font-bold mb-6 ${section.type === 'hero' ? 'text-white' : 'text-gray-800'}`}>
                {section.title}
              </h2>
            )}
            {section.content && (
              <div className={`prose max-w-none ${section.type === 'hero' ? 'text-white' : 'text-gray-600'}`}
                dangerouslySetInnerHTML={{ __html: section.content }}
              />
            )}
            {section.cards?.length > 0 && (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mt-8">
                {section.cards?.map((card) => (
                  <div key={card.id} className="bg-white rounded-xl shadow-lg p-6">
                    {card.title && (
                      <h3 className="text-xl font-semibold text-gray-800 mb-2">{card.title}</h3>
                    )}
                    {card.content && (
                      <p className="text-gray-600">{card.content}</p>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </section>
      ))}
    </div>
  );
}
